# .reviewer-config.sh — claude-code-reviewer configuration
# Generated by install.sh. Edit to match your project.
# Source: https://github.com/jazzsequence/claude-code-reviewer
#
# This file is sourced by the pre-commit hook. Keep it at the project root.
# Add it to .gitignore OR commit it — your choice. It contains no secrets.

# ── Test commands ─────────────────────────────────────────────────────────────
# Leave a variable empty ("") to skip that check entirely.

REVIEWER_TEST_CMD="npm test -- --run"   # unit tests
REVIEWER_LINT_CMD="npm run lint"        # linter
REVIEWER_BUILD_CMD="npm run build"      # build validation
REVIEWER_E2E_CMD=""                     # E2E tests (empty = skip)
                                        # example: "npm run test:e2e"

# ── Commit size limits (AI commits only) ──────────────────────────────────────
REVIEWER_MAX_FILES=5          # max staged files (excluding lock files)
REVIEWER_MAX_INSERTIONS=500   # max lines inserted

# ── Approval settings ─────────────────────────────────────────────────────────
REVIEWER_APPROVAL_TIMEOUT=300             # seconds before approval expires (default: 5min)
REVIEWER_APPROVAL_FILE="reviewer-approved" # filename; kept at project root

# ── File filtering ────────────────────────────────────────────────────────────
# Files matching this pattern skip the test suite (text-only changes)
REVIEWER_TEXT_ONLY_PATTERN='\.(md|txt|rst)$'

# Files excluded from the commit size count (machine-generated)
REVIEWER_EXCLUDED_FILES='^package-lock\.json$|^yarn\.lock$|^pnpm-lock\.yaml$|^composer\.lock$|^Gemfile\.lock$'
